public void testOptionGroupShortOnly() throws Exception
{
    OptionGroup group = new OptionGroup();
    group.addOption(OptionBuilder.create('a'));
    group.addOption(OptionBuilder.create('b'));

    Options options = new Options();
    options.addOptionGroup(group);

    CommandLine cl = parser.parse(options, new String[] { "-b" });

    assertTrue(cl.hasOption("b"));
    assertEquals("selected option", "b", group.getSelected());
}

public void testOptionGroupMixed() throws Exception
{
    OptionGroup group = new OptionGroup();
    group.addOption(OptionBuilder.hasArg().create('x'));
    group.addOption(OptionBuilder.withLongOpt("longopt").create());

    Options options = new Options();
    options.addOptionGroup(group);

    CommandLine cl = parser.parse(options, new String[] { "--longopt" });

    assertTrue(cl.hasOption("longopt"));
    assertEquals("selected option", "longopt", group.getSelected());
}

public void testOptionGroupReselect() throws Exception
{
    OptionGroup group = new OptionGroup();
    Option opt = OptionBuilder.withLongOpt("test").create();
    group.addOption(opt);

    Options options = new Options();
    options.addOptionGroup(group);

    CommandLine cl = parser.parse(options, new String[] { "--test" });

    assertTrue(cl.hasOption("test"));
    assertEquals("selected option", "test", group.getSelected());

    // Reselect the same option should not throw exception
    group.setSelected(opt);
    assertEquals("selected option", "test", group.getSelected());
}
